revision.text:
{{#switch:
  {{#if:{{{1|}}}
  | {{#ifexpr:{{PAGESINCATEGORY:{{PAGENAME}}|R}} >= {{{1|}}}
    | report
    | noreport
    }}
  | report
  }}

| noreport =
  {{cmbox   <!-- Cmbox since autoreport is only for category pages. -->
  | image = [[File:Edit-clear.svg|40x40px|link=|alt=]]
  | textstyle = text-align: center;
  | text = If this category gets {{{1|}}} {{plural:{{{1|}}}|item|items}} or more, it will report as a [[:Category:Wikipedia stub sorting backlog|backlog]]. <small>({{purge|recount}})</small>
  }}

| report
| #default =
  {{mbox
  | demospace = {{{demospace|}}}  <!-- For the examples in the /doc. -->
  | type = style
  | style = text-align: center;
  | text = This page has a '''[[:Category:Wikipedia stub sorting backlog|backlog]]''' that requires the attention of willing editors. <br> {{
    #if:{{{1|}}}
    | ''This notice will hide when this category has fewer than {{{1}}} {{plural:{{{1|}}}|item|items}}.'' <small>({{purge|recount}})</small>
    | ''Please remove this notice when the backlog is cleared.''
    }}
  }}<includeonly>{{#ifeq:{{SUBJECTSPACE}}|{{ns:user}}
  | <!-- Don't categorise when on user or user talk pages. -->
  | {{{category|[[Category:Wikipedia stub sorting backlog|{{PAGENAME}}]]}}}
  }}</includeonly>

}}<noinclude>
{{documentation}}
<!-- Add categories and interwikis to the /doc subpage, not here! -->
</noinclude>

